Map<String, List<int>> _rangeShape(FortuneRange range) => {
  'row': [range.rowStart, range.rowEnd],
  'column': [range.columnStart, range.columnEnd],
};

Offset _toolbarItemCenter(String key, {double width = 1200}) {
  for (final entry in fortuneVisibleToolbarItemRects(width)) {
    if (entry.key == key) {
      return entry.value.center;
    }
  }
  fail('toolbar item not found: $key');
}

Future<void> _openImageInsertDialog(
  WidgetTester tester, {
  double? width,
}) async {
  final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
  final toolbarWidth =
      width ?? tester.getSize(find.byType(FortuneSheetCanvas)).width;
  await tester.tapAt(
    topLeft +
        _toolbarItemCenter(fortuneToolbarImageCommand, width: toolbarWidth),
  );
  await tester.pumpAndSettle();
}

Future<void> _chooseImageForInsertDialog(
  WidgetTester tester, {
  Size size = const Size(1688, 600),
}) async {
  final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
  final rect = fortuneImageInsertDialogRect(size);
  await tester.tapAt(topLeft + fortuneImageInsertFileButtonRect(rect).center);
  await tester.pumpAndSettle();
}

Future<void> _confirmImageInsertDialog(
  WidgetTester tester, {
  Size size = const Size(1688, 600),
}) async {
  final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
  final rect = fortuneImageInsertDialogRect(size);
  await tester.tapAt(
    topLeft + fortuneImageInsertConfirmButtonRect(rect).center,
  );
  await tester.pumpAndSettle();
}

Future<void> _insertToolbarImage(
  WidgetTester tester, {
  Size size = const Size(1688, 600),
}) async {
  await _openImageInsertDialog(tester, width: size.width);
  await _chooseImageForInsertDialog(tester, size: size);
  await _confirmImageInsertDialog(tester, size: size);
}

