    void expectInsertedRowColumnSlotsEmpty(
      String type,
      int index,
      int count,
      String direction,
    ) {
      final sourceCells = <FortuneCellCoord, FortuneCell>{};
      if (type == 'row') {
        sourceCells[FortuneCellCoord(index, 0)] = const FortuneCell(value: 'A');
        sourceCells[FortuneCellCoord(index, 2)] = const FortuneCell(value: 'B');
      } else {
        sourceCells[FortuneCellCoord(0, index)] = const FortuneCell(value: 'A');
        sourceCells[FortuneCellCoord(2, index)] = const FortuneCell(value: 'B');
      }
      final inserted = insertRowOrColumn(
        FortuneSheet(
          id: 'insert-$type-$index-$count-$direction',
          name: 'InsertMatrix',
          rowCount: 6,
          columnCount: 6,
          cells: sourceCells,
        ),
        type,
        index,
        count,
        direction: direction,
      );
      final slotStart = direction == 'rightbottom' ? index + 1 : index;
      for (var offset = 0; offset < count; offset += 1) {
        for (var lineIndex = 0; lineIndex < 4; lineIndex += 1) {
          final coord = type == 'row'
              ? FortuneCellCoord(slotStart + offset, lineIndex)
              : FortuneCellCoord(lineIndex, slotStart + offset);
          expect(inserted.cells[coord], isNull);
        }
      }
    }

