    FortuneSheet matrixSheet(String id, int rowCount, int columnCount) {
      return FortuneSheet(
        id: id,
        name: 'DeleteMatrix',
        rowCount: rowCount,
        columnCount: columnCount,
        cells: {
          for (var rowIndex = 0; rowIndex < rowCount; rowIndex += 1)
            for (
              var columnIndex = 0;
              columnIndex < columnCount;
              columnIndex += 1
            )
              FortuneCellCoord(rowIndex, columnIndex): FortuneCell(
                value: '$rowIndex,$columnIndex',
              ),
        },
      );
    }

    void expectDeletedRowColumnMatrix(
      String type,
      int start,
      int end,
      int rowCount,
      int columnCount,
    ) {
      final source = matrixSheet(
        'delete-$type-$start-$end-$rowCount-$columnCount',
        rowCount,
        columnCount,
      );
      final deleted = deleteRowOrColumn(source, type, start, end);
      final maxIndex = type == 'row' ? rowCount - 1 : columnCount - 1;
      final deleteStart = math.min(math.max(0, math.min(start, end)), maxIndex);
      final deleteEnd = math.min(math.max(0, math.max(start, end)), maxIndex);
      final deleteCount = deleteEnd - deleteStart + 1;
      final nextRowCount = type == 'row' ? rowCount - deleteCount : rowCount;
      final nextColumnCount = type == 'column'
          ? columnCount - deleteCount
          : columnCount;
      expect(deleted.rowCount, nextRowCount);
      expect(deleted.columnCount, nextColumnCount);
      for (var rowIndex = 0; rowIndex < nextRowCount; rowIndex += 1) {
        for (
          var columnIndex = 0;
          columnIndex < nextColumnCount;
          columnIndex += 1
        ) {
          final sourceRow = type == 'row' && rowIndex >= deleteStart
              ? rowIndex + deleteCount
              : rowIndex;
          final sourceColumn = type == 'column' && columnIndex >= deleteStart
              ? columnIndex + deleteCount
              : columnIndex;
          expect(
            deleted.cells[FortuneCellCoord(rowIndex, columnIndex)]?.value,
            '$sourceRow,$sourceColumn',
          );
        }
      }
    }

