    void expectMergeMatrix(int r0, int c0, int r1, int c1, String mode) {
      final range = FortuneRange(
        rowStart: r0,
        rowEnd: r1,
        columnStart: c0,
        columnEnd: c1,
      );
      final merged = FortuneSheet(
        id: 'merge-$mode',
        name: 'MergeMatrix',
      ).mergeCells(range, mode);
      for (var row = r0; row <= r1; row += 1) {
        for (var column = c0; column <= c1; column += 1) {
          final merge = merged.cells[FortuneCellCoord(row, column)]?.merge;
          switch (mode) {
            case 'merge-all':
              expect(merge?.row, r0);
              expect(merge?.column, c0);
              expect(
                merge?.rowSpan,
                row == r0 && column == c0 ? r1 - r0 + 1 : 1,
              );
              expect(
                merge?.columnSpan,
                row == r0 && column == c0 ? c1 - c0 + 1 : 1,
              );
            case 'merge-horizontal':
              expect(merge?.row, row);
              expect(merge?.column, c0);
              expect(merge?.rowSpan, 1);
              expect(merge?.columnSpan, column == c0 ? c1 - c0 + 1 : 1);
            case 'merge-vertical':
              expect(merge?.row, r0);
              expect(merge?.column, column);
              expect(merge?.rowSpan, row == r0 ? r1 - r0 + 1 : 1);
              expect(merge?.columnSpan, 1);
          }
        }
      }
      final canceled = merged.cancelMerge(range);
      for (var row = r0; row <= r1; row += 1) {
        for (var column = c0; column <= c1; column += 1) {
          expect(canceled.cells[FortuneCellCoord(row, column)]?.merge, isNull);
        }
      }
    }

    final upstreamMergeCases = [
      (0, 0, 1, 1, 'merge-all'),
      (0, 0, 1, 1, 'merge-vertical'),
      (0, 0, 1, 1, 'merge-horizontal'),
      (0, 0, 3, 1, 'merge-all'),
      (0, 0, 3, 1, 'merge-vertical'),
      (0, 0, 3, 3, 'merge-horizontal'),
      (2, 1, 3, 1, 'merge-all'),
      (2, 1, 3, 1, 'merge-vertical'),
      (2, 1, 3, 1, 'merge-horizontal'),
      (1, 2, 3, 3, 'merge-all'),
      (1, 2, 3, 3, 'merge-vertical'),
      (1, 2, 3, 3, 'merge-horizontal'),
    ];
    for (final (r0, c0, r1, c1, mode) in upstreamMergeCases) {
      expectMergeMatrix(r0, c0, r1, c1, mode);
    }
