  test(
    'resizeSheetGridClientArea stores millimeters without clearing sheet data',
    () {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 'sheet1',
            name: 'Sheet1',
            rowCount: 12,
            columnCount: 8,
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(value: 'old'),
            },
            rowHeights: const {0: 44},
            columnWidths: const {0: 88},
          ),
        ],
      );

      final resized = resizeSheetGridClientArea(workbook, 80, 40);
      final sheet = resized.activeSheet;

      expect(sheet.id, 'sheet1');
      expect(sheet.rowCount, 12);
      expect(sheet.columnCount, 8);
      expect(sheet.cells[const FortuneCellCoord(0, 0)]?.value, 'old');
      expect(sheet.rowHeights[0], 44);
      expect(sheet.columnWidths[0], 88);
      expect(fortuneSheetGridClientWidthMm(sheet), 80);
      expect(fortuneSheetGridClientHeightMm(sheet), 40);
      final physicalSize = fortuneSheetGridClientPhysicalSize(sheet)!;
      expect(physicalSize.widthMm, 80);
      expect(physicalSize.heightMm, 40);
      expect(
        physicalSize.logicalSize.width,
        closeTo(fortuneMillimetersToLogicalPixels(80), 0.001),
      );
      expect(
        physicalSize.logicalSize.height,
        closeTo(fortuneMillimetersToLogicalPixels(40), 0.001),
      );
      expect(
        physicalSize.pixelsAtDpi(203).width,
        closeTo(fortuneMillimetersToPixels(80, 203), 0.001),
      );
      expect(
        physicalSize.pixelsAtDpi(203).height,
        closeTo(fortuneMillimetersToPixels(40, 203), 0.001),
      );
    },
  );

  test('resizeSheetGridClientArea rejects non-positive millimeters', () {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 'sheet1', name: 'Sheet1')],
    );

    expect(
      () => resizeSheetGridClientArea(workbook, 0, 40),
      throwsA(same(INVALID_PARAMS)),
    );
    expect(
      () => resizeSheetGridClientArea(workbook, 80, -1),
      throwsA(same(INVALID_PARAMS)),
    );
    expect(
      () => fortuneMillimetersToPixels(80, 0),
      throwsA(same(INVALID_PARAMS)),
    );
