  test('clearSheet resets a sheet in place through the public API', () {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 'before', name: 'Before', order: 0),
        FortuneSheet(
          id: 'label-sheet',
          name: 'Labels',
          order: 1,
          rowCount: 99,
          columnCount: 88,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'text'),
          },
          rowHeights: const {0: 42},
          columnWidths: const {1: 120},
          customHeight: const {0: 42},
          customWidth: const {1: 120},
          hiddenRows: const {2},
          hiddenColumns: const {3},
          rawMerge: const {'0_0': <String, Object?>{}},
          hasRawMerge: true,
          filter: const {'rowhidden': <String, Object?>{}},
          rawFilter: const {'rowhidden': <String, Object?>{}},
          hasRawFilter: true,
          hyperlinks: const {'0_0': 'https://example.test'},
          conditionFormats: const [
            {'type': 'cellIs'},
          ],
          hasRawConditionFormats: true,
          dynamicArray: const [
            {'r': 0, 'c': 0},
          ],
          hasRawDynamicArray: true,
          selectionSave: const [
            {
              'row': [0, 0],
              'column': [0, 0],
            },
          ],
          hasRawSelectionSave: true,
          status: 0,
        ),
        FortuneSheet(id: 'after', name: 'After', order: 2),
      ],
      activeSheetIndex: 1,
    );

    final clearedWorkbook = clearSheet(
      workbook,
      id: 'label-sheet',
      rowCount: 12,
      columnCount: 8,
    );
    final clearedSheet = clearedWorkbook.activeSheet;

    expect(clearedWorkbook.sheets.map((sheet) => sheet.id), [
      'before',
      'label-sheet',
      'after',
    ]);
    expect(clearedWorkbook.activeSheetIndex, 1);
    expect(clearedSheet.id, 'label-sheet');
    expect(clearedSheet.name, 'Labels');
    expect(clearedSheet.order, 1);
    expect(clearedSheet.status, 0);
    expect(clearedSheet.rowCount, 12);
    expect(clearedSheet.columnCount, 8);
    expect(clearedSheet.cells, isEmpty);
    expect(clearedSheet.rowHeights, isEmpty);
    expect(clearedSheet.columnWidths, isEmpty);
    expect(clearedSheet.customHeight, isEmpty);
    expect(clearedSheet.customWidth, isEmpty);
    expect(clearedSheet.hiddenRows, isEmpty);
    expect(clearedSheet.hiddenColumns, isEmpty);
    expect(clearedSheet.rawMerge, isNull);
    expect(clearedSheet.hasRawMerge, isFalse);
    expect(clearedSheet.filter, isEmpty);
    expect(clearedSheet.hasRawFilter, isFalse);
    expect(clearedSheet.hyperlinks, isEmpty);
    expect(clearedSheet.conditionFormats, isNull);
    expect(clearedSheet.hasRawConditionFormats, isFalse);
    expect(clearedSheet.dynamicArray, isNull);
    expect(clearedSheet.hasRawDynamicArray, isFalse);
    expect(clearedSheet.selectionSave, isNull);
    expect(clearedSheet.hasRawSelectionSave, isFalse);
    expect(clearSheet(workbook, index: 1).activeSheet.rowCount, isNull);
    expect(workbook.clearSheet('missing').sheets.map((sheet) => sheet.id), [
      'before',
      'label-sheet',
      'after',
    ]);
  });

  test('public API context shims preserve fallback branches', () {
    final canvasContext = <String, Object?>{};
    updateContextWithCanvas(
      canvasContext,
      placeholderWidth: 101,
      placeholderHeight: 51,
    );
    expect(canvasContext['cellmainWidth'], 55);
    expect(canvasContext['cellmainHeight'], 31);
    expect(canvasContext['canvasSize'], {'width': 101, 'height': 51});

    final axisContext = <String, Object?>{
      'defaultrowlen': 10,
      'defaultcollen': 20,
      'config': {
        'rowlen': {0: 4},
        'columnlen': {0: 9},
      },
    };
    updateContextWithSheetData(axisContext, const [
      ['A1'],
      ['A2'],
    ]);
    expect(axisContext['visibledatarow'], [5, 16]);
    expect(axisContext['visibledatacolumn'], [10]);

    final emptyRefreshContext = <String, Object?>{'currentSheetId': 'sheet-1'};
    jfrefreshgrid(emptyRefreshContext);
    expect(emptyRefreshContext.containsKey('refreshRange'), isFalse);

    final refreshContext = <String, Object?>{
      'currentSheetId': 'sheet-1',
      'luckysheet_select_save': const [
        FortuneRange(rowStart: 1, rowEnd: 1, columnStart: 2, columnEnd: 2),
      ],
      'flowdata': const [
        ['A1'],
      ],
      'formulaCache': 'preserve',
    };
    jfrefreshgrid(refreshContext, isRunExecFunction: false);
    expect(refreshContext['refreshRange'], [
      {
        'row': [1, 1],
        'column': [2, 2],
      },
    ]);
    expect(refreshContext['refreshData'], [
      ['A1'],
    ]);
    expect(refreshContext['formulaCache'], 'preserve');

    expect(
      getrangeseleciton(
        anchorText: '   ',
        anchorOffset: 1,
        anchorParentIsSpan: true,
        previousSiblingText: ' B2 ',
      ),
      {'source': 'previousSibling', 'text': 'B2'},
    );
    expect(
      getrangeseleciton(
        anchorElementId: 'luckysheet-functionbox-cell',
        spans: const [' A1 '],
      ),
      {'source': 'editorSpan', 'text': 'A1', 'index': 0},
    );
    expect(getrangeseleciton(anchorOffset: 0, previousSiblingText: ' C3 '), {
      'source': 'previousSibling',
      'text': 'C3',
    });
    expect(
      getrangeseleciton(anchorElementId: 'luckysheet-rich-text-editor'),
      isNull,
    );

    final emptyHighlightContext = <String, Object?>{'keep': true};
    rangeHightlightselected(emptyHighlightContext, selectionText: '  ');
    expect(emptyHighlightContext, {'keep': true});

    final formulaContext = <String, Object?>{};
    handleFormulaInput(
      formulaContext,
      editorText: '=',
      copyToId: 'luckysheet-functionbox-cell',
    );
    expect(formulaContext['formulaInputHtml'], isNotNull);
    expect((formulaContext['formulaCache'] as Map)['functionRangeIndex'], [
      0,
      1,
    ]);

    final imeContext = <String, Object?>{};
    handleFormulaInput(
      imeContext,
      editorText: '=A1',
      keyCode: 229,
      copyToId: 'luckysheet-functionbox-cell',
    );
    expect(imeContext.containsKey('formulaInputHtml'), isFalse);
    expect(imeContext.containsKey('formulaCopyTo'), isFalse);

    final plainContext = <String, Object?>{};
    handleFormulaInput(
      plainContext,
      editorText: '<b>plain</b>',
      preText: '=A1',
      copyToId: 'luckysheet-functionbox-cell',
    );
    expect(plainContext['formulaInputHtml'], '&lt;b&gt;plain&lt;/b&gt;');
    expect(plainContext['formulaCopyTo'], {
      'id': 'luckysheet-functionbox-cell',
      'html': '&lt;b&gt;plain&lt;/b&gt;',
    });

    final nonFormulaCopyContext = <String, Object?>{};
    handleFormulaInput(
      nonFormulaCopyContext,
      editorText: '<i>plain</i>',
      copyToId: 'luckysheet-functionbox-cell',
    );
    expect(nonFormulaCopyContext['formulaCopyTo'], {
      'id': 'luckysheet-functionbox-cell',
      'html': '&lt;i&gt;plain&lt;/i&gt;',
    });
  });

