  testWidgets('FortuneSheetApp attaches controller for widget lifetime', (
    tester,
  ) async {
    final firstController = FortuneSheetController();
    final secondController = FortuneSheetController();

    expect(firstController.isAttached, isFalse);
    expect(secondController.isAttached, isFalse);

    await tester.pumpWidget(
      SizedBox(
        width: 320,
        height: 240,
        child: FortuneSheetApp(controller: firstController),
      ),
    );
    await tester.pump();

    expect(firstController.isAttached, isTrue);
    expect(firstController.getSelection(), isNotNull);
    expect(secondController.isAttached, isFalse);

    await tester.pumpWidget(
      SizedBox(
        width: 320,
        height: 240,
        child: FortuneSheetApp(controller: secondController),
      ),
    );
    await tester.pump();

    expect(firstController.isAttached, isFalse);
    expect(secondController.isAttached, isTrue);

    await tester.pumpWidget(const SizedBox());
    await tester.pump();

    expect(firstController.isAttached, isFalse);
    expect(secondController.isAttached, isFalse);
  });

