        of: rotationInput,
        matching: find.byType(EditableText),
      );

      expect(tester.widget<EditableText>(widthField).controller.text, '200');
      expect(tester.widget<EditableText>(heightField).controller.text, '100');

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      final rect = fortuneImageInsertDialogRect(const Size(1688, 600));
      final selectionBeforeDialogKey = painter().selection;
      await tester.sendKeyEvent(LogicalKeyboardKey.arrowRight);
      await tester.pump();
      expect(painter().selection.row, selectionBeforeDialogKey.row);
      expect(painter().selection.column, selectionBeforeDialogKey.column);

