      tester.testTextInput.enterText('5');
      await tester.pump();
      expect(tester.widget<EditableText>(widthField).controller.text, '5');

      await tester.enterText(widthField, '200');
      await tester.pump();
      final widthInputRect = tester.getRect(widthInput);
      await tester.dragFrom(
        widthInputRect.centerRight - const Offset(2, 0),
        Offset(-widthInputRect.width + 4, 0),
      );
      await tester.pump();
      expect(
        tester
            .widget<EditableText>(widthField)
            .controller
            .selection
            .isCollapsed,
        isFalse,
      );

      final scrollBeforeDialogWheel = painter().scrollOffset;
      await tester.sendEventToBinding(
        PointerScrollEvent(
          position: topLeft + rect.center,
          scrollDelta: const Offset(0, 120),
        ),
      );
      await tester.pump();
      expect(painter().scrollOffset, scrollBeforeDialogWheel);

      expect(painter().imageInsertAspectLocked, isTrue);

      await tester.tapAt(
        topLeft + fortuneImageInsertLinkButtonRect(rect).center,
      );
      await tester.pump();
      expect(painter().imageInsertAspectLocked, isFalse);

      await tester.enterText(widthField, '50');
      await tester.pump();
      expect(tester.widget<EditableText>(heightField).controller.text, '100');

      await tester.tapAt(
        topLeft + fortuneImageInsertLinkButtonRect(rect).center,
      );
      await tester.pump();
      expect(painter().imageInsertAspectLocked, isTrue);

      await tester.enterText(widthField, '60');
      await tester.pump();
      expect(tester.widget<EditableText>(heightField).controller.text, '30');

      await tester.tapAt(
        topLeft + fortuneImageInsertRotateButtonRect(rect).center,
      );
      await tester.pump();
      expect(tester.widget<EditableText>(rotationField).controller.text, '90');

      await _confirmImageInsertDialog(tester);

      final image = painter().workbook.activeSheet.images.single;
      expect(image.src, 'data:image/png;base64,CQgH');
      expect(image.width, moreOrLessEquals(60, epsilon: 0.01));
      expect(image.height, moreOrLessEquals(30, epsilon: 0.01));
      expect(image.extraFields['rotation'], 90);
      expect(image.extraFields.containsKey('widthMm'), isFalse);
      expect(image.extraFields.containsKey('heightMm'), isFalse);
    },
  );

