  test('FortuneSheet image insert dialog controls do not overlap labels', () {
    final rect = fortuneImageInsertDialogRect(const Size(1688, 600));
    final close = fortuneImageInsertCloseButtonRect(rect);
    expect(close.width, lessThan(18));
    expect(close.height, lessThan(18));

    final widthUnit = fortuneImageInsertWidthUnitRect(rect);
    final heightUnit = fortuneImageInsertHeightUnitRect(rect);
    final rotationUnit = fortuneImageInsertRotationUnitRect(rect);
    final linkButton = fortuneImageInsertLinkButtonRect(rect);
    final rotateButton = fortuneImageInsertRotateButtonRect(rect);
    final confirmButton = fortuneImageInsertConfirmButtonRect(rect);

    expect(widthUnit.overlaps(linkButton), isFalse);
    expect(heightUnit.overlaps(linkButton), isFalse);
    expect(rotationUnit.overlaps(rotateButton), isFalse);
    expect(widthUnit.right, lessThanOrEqualTo(linkButton.left));
    expect(heightUnit.right, lessThanOrEqualTo(linkButton.left));
    expect(rotationUnit.right, lessThanOrEqualTo(rotateButton.left));
    expect(confirmButton.top - rotateButton.bottom, greaterThanOrEqualTo(18));
  });

