  testWidgets('FortuneSheetApp rotates selected image from rotation handle', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 'image-rotation-sheet',
          name: 'ImageRotation',
          images: [
            FortuneImage(
              id: 'rotating-image',
              src: 'missing.png',
              left: 80,
              top: 70,
              width: 120,
              height: 80,
            ),
          ],
        ),
      ],
    );

    await tester.pumpWidget(
      SizedBox(
        width: 800,
        height: 500,
        child: FortuneSheetApp(workbook: workbook),
      ),
    );
    await tester.pump();

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final settings = painter().workbook.settings;
    final image = painter().workbook.activeSheet.images.single;
    final zoomRatio = painter().workbook.activeSheet.zoomRatio <= 0
        ? 1.0
        : painter().workbook.activeSheet.zoomRatio;
    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final imageRect = ui.Rect.fromLTWH(
      settings.rowHeaderWidth + image.left * zoomRatio,
      settings.effectiveToolbarHeight +
          settings.effectiveFormulaBarHeight +
          settings.columnHeaderHeight +
          image.top * zoomRatio,
      image.width * zoomRatio,
      image.height * zoomRatio,
    );

    await tester.tapAt(topLeft + imageRect.center);
    await tester.pump();
    expect(painter().activeImageId, 'rotating-image');

    final rotationHandle = Offset(imageRect.center.dx, imageRect.top - 32);
    final rightOfCenter = imageRect.center + const Offset(80, 0);
    await tester.dragFrom(
      topLeft + rotationHandle,
      rightOfCenter - rotationHandle,
    );
    await tester.pump();

    final rotated = painter().workbook.activeSheet.images.single;
    expect(rotated.left, image.left);
    expect(rotated.top, image.top);
    expect(rotated.width, image.width);
    expect(rotated.height, image.height);
    expect(rotated.extraFields['rotation'], closeTo(90, 0.5));
  });

