  testWidgets('FortuneSheetApp emits external image edits through callbacks', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final changes = <FortuneWorkbook>[];
    final ops = <List<FortuneOp>>[];
    Future<FortuneImagePickResult?> imagePicker() async {
      return FortuneImagePickResult(
        bytes: Uint8List.fromList([6, 7, 8]),
        fileName: 'external-change.png',
        mimeType: 'image/png',
        width: 20,
        height: 22,
      );
    }

    final externalWorkbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 'external', name: 'External')],
    );

    await tester.pumpWidget(
      SizedBox(
        width: 1688,
        height: 600,
        child: FortuneSheetApp(
          workbook: externalWorkbook,
          imagePicker: imagePicker,
          onChange: changes.add,
          onOp: ops.add,
        ),
      ),
    );
    await tester.pump();

    expect(changes, hasLength(1));
    expect(changes.single.activeSheet.id, 'external');
    expect(changes.single.activeSheet.images, isEmpty);
    expect(ops, isEmpty);

    await _insertToolbarImage(tester);

    final changedImages = changes.last.activeSheet.images;
    expect(changes, hasLength(2));
    expect(changes.last.activeSheet.id, 'external');
    expect(changedImages, hasLength(1));
    expect(changedImages.single.src, 'data:image/png;base64,BgcI');
    expect(changedImages.single.width, moreOrLessEquals(10, epsilon: 0.01));
    expect(changedImages.single.height, moreOrLessEquals(11, epsilon: 0.01));
    expect(changedImages.single.extraFields['originWidth'], 20);
    expect(changedImages.single.extraFields['originHeight'], 22);

    expect(ops, hasLength(1));
    expect(ops.single, hasLength(1));
    expect(ops.single.first['op'], 'replace');
    expect(ops.single.first['id'], 'external');
    expect(ops.single.first['path'], ['images']);

    final images = ops.single.first['value']! as List<Object?>;
    expect(images, hasLength(1));
    final image = images.single! as Map<Object?, Object?>;
    expect(
      image['id'],
      isA<String>().having((id) => id, 'id', startsWith('img_')),
    );
    expect(image['src'], 'data:image/png;base64,BgcI');
    expect(image['width'], moreOrLessEquals(10, epsilon: 0.01));
    expect(image['height'], moreOrLessEquals(11, epsilon: 0.01));
    expect(image['originWidth'], 20);
    expect(image['originHeight'], 22);
  });

