  test('FortuneCustomToolbarItem serializes public metadata safely', () {
    void onClick(FortuneCustomToolbarItem item) {}

    final children = {
      'label': 'Refresh',
      'items': ['reload'],
    };
    final icon = {
      'name': 'refresh',
      'style': {'color': '#00f'},
    };
    final item = FortuneCustomToolbarItem(
      key: 'custom-refresh',
      tooltip: 'Refresh data',
      children: children,
      iconName: 'search',
      icon: icon,
      onClick: onClick,
    );

    final json = item.toJson();
    (children['items']! as List).add('stale');
    (icon['style']! as Map)['color'] = '#f00';

    expect(json, {
      'key': 'custom-refresh',
      'tooltip': 'Refresh data',
      'children': {
        'label': 'Refresh',
        'items': ['reload'],
      },
      'iconName': 'search',
      'icon': {
        'name': 'refresh',
        'style': {'color': '#00f'},
      },
    });
    expect(json, isNot(contains('onClick')));

    ((json['children']! as Map)['items']! as List).add('json-only');
    ((json['icon']! as Map)['style']! as Map)['color'] = '#0f0';
    expect(children, {
      'label': 'Refresh',
      'items': ['reload', 'stale'],
    });
    expect(icon, {
      'name': 'refresh',
      'style': {'color': '#f00'},
    });

    expect(const FortuneCustomToolbarItem(key: 'minimal').toJson(), {
      'key': 'minimal',
    });
  });

