  test('Fortune value objects expose stable public semantics', () {
    const coord = FortuneCellCoord(2, 3);
    const sameCoord = FortuneCellCoord(2, 3);
    const otherCoord = FortuneCellCoord(3, 2);
    final cells = {coord: const FortuneCell(value: 'A')};

    expect(coord, sameCoord);
    expect(coord.hashCode, sameCoord.hashCode);
    expect(coord, isNot(otherCoord));
    expect(cells[sameCoord]?.value, 'A');

    const single = FortuneSelection(row: 4, column: 5);
    expect(single.rowEnd, 4);
    expect(single.columnEnd, 5);
    expect(single.rowStart, 4);
    expect(single.normalizedRowEnd, 4);
    expect(single.columnStart, 5);
    expect(single.normalizedColumnEnd, 5);
    expect(single.isSingleCell, isTrue);

    const reversed = FortuneSelection(
      row: 7,
      column: 6,
      rowEnd: 2,
      columnEnd: 1,
    );
    expect(reversed.rowStart, 2);
    expect(reversed.normalizedRowEnd, 7);
    expect(reversed.columnStart, 1);
    expect(reversed.normalizedColumnEnd, 6);
    expect(reversed.isSingleCell, isFalse);

    const frozenBoth = FortuneFrozenPane(
      type: 'rangeBoth',
      rowFocus: 99,
      columnFocus: -2,
    );
    expect(frozenBoth.freezesRows, isTrue);
    expect(frozenBoth.freezesColumns, isTrue);
    expect(frozenBoth.rowFocusIndex(4), 3);
    expect(frozenBoth.columnFocusIndex(4), 0);
    expect(frozenBoth.rowFocusIndex(0), isNull);

    const frozenRow = FortuneFrozenPane(type: 'row');
    expect(frozenRow.freezesRows, isTrue);
    expect(frozenRow.freezesColumns, isFalse);
    expect(frozenRow.columnFocusIndex(4), isNull);
  });

