  test('formula search logical functions expose detailed help seeds', () {
    final logicalFunctions = fortuneFormulaSearchFunctions.where(
      (function) => function.categoryType == 10,
    );
    final functionsByName = {
      for (final function in logicalFunctions) function.name: function,
    };

    expect(
      functionsByName['IF']?.exampleSignature,
      'IF(A2 = "foo", "A2 is foo", "A2 was false")',
    );
    expect(
      functionsByName['IF']?.parameters.last.displayName,
      '[value_if_false]',
    );
    expect(
      functionsByName['IFS']?.exampleSignature,
      'IFS(FALSE, 1/0, TRUE, "matched")',
    );
    expect(functionsByName['IFS']?.parameters.last.repeat, isTrue);
    expect(
      functionsByName['SWITCH']?.exampleSignature,
      'SWITCH("b", "a", 1/0, "b", "bee", "fallback")',
    );
    expect(functionsByName['SWITCH']?.parameters[3].repeat, isTrue);
    expect(
      functionsByName['AND']?.parameters.last.displayName,
      '[logical_expression2, ...]',
    );
    expect(
      functionsByName['OR']?.exampleSignature,
      'OR(A2 = "foo",  A3 = "bar")',
    );
    expect(functionsByName['XOR']?.exampleSignature, 'XOR(TRUE(), FALSE())');
    expect(functionsByName['NOT']?.exampleSignature, 'NOT(A2)');
    expect(
      functionsByName['TRUE']?.detail,
      'Returns the logical value `TRUE`.',
    );
    expect(functionsByName['TRUE']?.exampleSignature, isEmpty);
    expect(
      functionsByName['FALSE']?.detail,
      'Returns the logical value `FALSE`.',
    );
    expect(functionsByName['FALSE']?.exampleSignature, isEmpty);
    expect(
      functionsByName['IFERROR']?.exampleSignature,
      'IFERROR(A1, "Error in cell A1")',
    );
    expect(functionsByName['IFNA']?.exampleSignature, 'IFNA(NA(), "missing")');
    expect(
      logicalFunctions.where((function) => !function.hasDetailedHelp),
      isEmpty,
    );

    expect(
      fortuneFormulaSearchSelectedExampleSignature('iferror', 10, 0),
      'IFERROR(A1, "Error in cell A1")',
    );
    expect(
      fortuneFormulaSearchSelectedDetailedDescription('not', 10, 0),
      'Returns the opposite of a logical value - `NOT(TRUE)` returns `FALSE`; `NOT(FALSE)` returns `TRUE`.',
    );
  });

