        functionsByName['QUARTILE_EXC']?.detail,
        contains('exclusive of 0 and 4'),
      );
      expect(
        functionsByName['QUARTILE.EXC']?.exampleSignature,
        'QUARTILE.EXC(A2:A100, 3)',
      );
      expect(
        functionsByName['QUARTILE_INC']?.exampleSignature,
        'QUARTILE_INC(A2:A100, 3)',
      );
      expect(
        functionsByName['QUARTILE.INC']?.exampleSignature,
        'QUARTILE.INC(A2:A100, 3)',
      );

      expect(
        fortuneFormulaSearchSelectedExampleSignature(
          'normal distribution',
          1,
          2,
        ),
        'CONFIDENCE.NORM(0.05, 1.6, 250)',
      );
      expect(
        fortuneFormulaSearchSelectedDetailedDescription('poisson', 1, 0),
        'Returns the value of the Poisson distribution function (or Poisson cumulative distribution function) for a specified value and mean.',
      );
    },
  );

  test(
    'formula search statistical test and variance functions expose detailed help seeds',
    () {
      final statisticalFunctions = fortuneFormulaSearchFunctions.where(
        (function) => function.categoryType == 1,
      );
      final functionsByName = {
        for (final function in statisticalFunctions) function.name: function,
      };

      expect(
        functionsByName['T_INV_2T']?.exampleSignature,
        'T_INV_2T(0.35, 1)',
      );
      expect(
        functionsByName['T.INV.2T']?.exampleSignature,
        'T.INV.2T(0.35, 1)',
      );
      expect(
        functionsByName['T_TEST']?.exampleSignature,
        'T_TEST(A1:A4, B1:B4, 2, 1)',
      );
      expect(
        functionsByName['T.TEST']?.exampleSignature,
        'T.TEST(A1:A4, B1:B4, 2, 1)',
      );
      expect(
        functionsByName['TTEST']?.exampleSignature,
        'TTEST(A1:A4, B1:B4, 2, 1)',
      );
      expect(
        functionsByName['CONFIDENCE.T']?.exampleSignature,
        'CONFIDENCE.T(0.5, 1, 5)',
      );
      expect(
        functionsByName['F.TEST']?.exampleSignature,
        'F.TEST({1,2,3}, {2,4,8})',
      );
      expect(
        functionsByName['FTEST']?.exampleSignature,
        'FTEST({1,2,3}, {2,4,8})',
      );
      for (final name in <String>[
        'STDEV',
        'STDEVS',
        'STDEVP',
        'STDEV.P',
        'STDEVPA',
        'VAR',
        'VAR_S',
        'VARS',
        'VAR_P',
        'VAR.P',
        'VARP',
        'VARA',
        'VARPA',
      ]) {
        expect(functionsByName[name]?.exampleSignature, '$name(1, 2)');
        expect(
          functionsByName[name]?.parameters.last.displayName,
          '[value2, ...]',
        );
      }
      expect(functionsByName['SKEW_P']?.exampleSignature, 'SKEW_P(1, 2)');
      expect(functionsByName['SKEWP']?.exampleSignature, 'SKEWP(1, 2)');
      expect(functionsByName['SKEW_P']?.detail, contains('population'));
      expect(functionsByName['SKEWP']?.detail, contains('population'));
      expect(
        functionsByName['Z_TEST']?.parameters.last.displayName,
        '[standard_deviation]',
      );
      expect(
        functionsByName['ZTEST']?.parameters.last.displayName,
        '[standard_deviation]',
      );
      expect(functionsByName['T.TEST']?.detail, contains("Student's t-test"));
      expect(functionsByName['VARA']?.detail, contains('sample'));
      expect(functionsByName['VARPA']?.detail, contains('entire population'));
      expect(
        statisticalFunctions.where((function) => !function.hasDetailedHelp),
        isEmpty,
      );

      expect(
        fortuneFormulaSearchSelectedExampleSignature('t-test', 1, 0),
        'T_TEST(A1:A4, B1:B4, 2, 1)',
      );
      expect(
        fortuneFormulaSearchSelectedDetailedDescription('varpa', 1, 0),
        'Calculates the variance based on an entire population, setting text to the value `0`.',
      );
    },
  );

