  testWidgets('adjusted sheet print area boundary shows delayed tooltip', (
    tester,
  ) async {
    const settings = FortuneSettings();
    final workbook = FortuneWorkbook(
      settings: settings,
      sheets: [
        FortuneSheet(
          id: 'adjusted-print-tooltip',
          name: 'AdjustedPrintTooltip',
          rowCount: 20,
          columnCount: 20,
        ),
      ],
    );

    await tester.pumpWidget(
      SizedBox(
        width: 500,
        height: 300,
        child: FortuneSheetApp(
          workbook: workbook,
          gridClientSize: FortuneSheetGridClientPhysicalSize(
            widthMm: 25,
            heightMm: 30,
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() =>
        tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final dataLeft = settings.rowHeaderWidth * 2;
    final dataTop = sheetTop + settings.columnHeaderHeight * 2;
    final boundaryX = dataLeft + fortuneMillimetersToLogicalPixels(25);
    await tester.sendEventToBinding(
      PointerHoverEvent(position: topLeft + Offset(boundaryX, dataTop + 20)),
    );
    await tester.pump(const Duration(milliseconds: 499));
    expect(painter().sheetRulerTooltipText, isNull);

    await tester.pump(const Duration(milliseconds: 1));
    expect(painter().sheetRulerTooltipText, '라벨 영역');

    await tester.pump(const Duration(seconds: 1));
    expect(painter().sheetRulerTooltipText, isNull);
  });

