  testWidgets('FortuneSheetApp falls back from malformed saved selection', (
    tester,
  ) async {
    Future<FortuneSelection> selectionFor(
      Object? selectionSave,
      String key,
    ) async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 'saved-selection-$key',
            name: 'Saved Selection $key',
            selectionSave: selectionSave,
            hasRawSelectionSave: selectionSave != null,
          ),
        ],
      );

      await tester.pumpWidget(
        SizedBox(
          width: 320,
          height: 240,
          child: FortuneSheetApp(
            key: ValueKey('saved-selection-$key'),
            workbook: workbook,
          ),
        ),
      );

      final painter =
          tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
              as FortuneSheetPainter;
      return painter.selection;
    }

    void expectSelection(
      FortuneSelection selection, {
      required int row,
      required int column,
      required int rowEnd,
      required int columnEnd,
    }) {
      expect(selection.row, row);
      expect(selection.column, column);
      expect(selection.rowEnd, rowEnd);
      expect(selection.columnEnd, columnEnd);
    }

    for (final entry in <String, Object?>{
      'missing': null,
      'empty': const [],
      'non-list': 'A1:B2',
      'non-map': const ['A1:B2'],
      'missing-column': const [
        {
          'row': [1, 2],
        },
      ],
      'bad-coordinate': const [
        {
          'row': [1, 'bad'],
          'column': [2, 3],
        },
      ],
    }.entries) {
      expectSelection(
        await selectionFor(entry.value, entry.key),
        row: 0,
        column: 0,
        rowEnd: 0,
        columnEnd: 0,
      );
    }

    expectSelection(
      await selectionFor(const [
        {
          'row': [4, 2],
          'column': [6, 3],
          'row_focus': 2,
          'column_focus': 3,
        },
      ], 'reversed'),
      row: 2,
      column: 3,
      rowEnd: 4,
      columnEnd: 6,
    );
  });

