  testWidgets('FortuneSheetApp updates facade props across fallback rebuilds', (
    tester,
  ) async {
    Future<FortuneImagePickResult?> firstPicker() async => null;
    Future<FortuneImagePickResult?> secondPicker() async => null;

    await tester.pumpWidget(
      FortuneSheetApp(
        imagePicker: firstPicker,
        locale: const FortuneSheetLocale(ok: 'Apply'),
      ),
    );

    FortuneSheetCanvas canvas() {
      return tester.widget<FortuneSheetCanvas>(find.byType(FortuneSheetCanvas));
    }

    final fallbackWorkbook = canvas().workbook;
    expect(canvas().imagePicker, same(firstPicker));
    expect(canvas().locale.ok, 'Apply');

    await tester.pumpWidget(
      FortuneSheetApp(
        imagePicker: secondPicker,
        locale: const FortuneSheetLocale(ok: 'Confirm'),
      ),
    );
    await tester.pump();

    expect(canvas().workbook, same(fallbackWorkbook));
    expect(canvas().imagePicker, same(secondPicker));
    expect(canvas().locale.ok, 'Confirm');
  });

